// ============================================================
// WORKFLOW CONFIGURATION — edit these values before going live
// ============================================================
return [{
  json: {

    // --- SEOZoom ---
    // IMPORTANT: Verify the correct endpoint with SEOZoom support.
    // Their API documentation is at https://suite.seozoom.it/api-docs/
    // The URL below is a PLACEHOLDER — confirm before deployment.
    seozoom_endpoint: 'https://apiv2.seozoom.com/api/v2/keywords/',

    // SEOZoom query parameters — verify field names with their docs
    seozoom_country: 'it',
    seozoom_language: 'it',
    seozoom_limit: 50,
    seozoom_min_volume: 100,

    // --- WordPress ---
    wordpress_url: 'https://www.studiolegalepasian.it',
    // NEVER change post_status to 'publish'
    wordpress_post_status: 'draft',

    // --- Content ---
    content_language: 'italiano',
    content_min_words: 900,
    content_min_h2_count: 3,
    content_min_faq_count: 3,
    meta_title_max_chars: 60,
    meta_description_max_chars: 160,

    // --- Firm identity (used in prompts and disclaimer) ---
    firm_name: 'Studio Legale Pasian',
    firm_city: 'Italia',
    firm_phone: '+39 000 000 0000',
    firm_email: 'info@studiolegalepasian.it',
    firm_practice_areas: 'diritto di famiglia, diritto civile, diritto penale, diritto del lavoro, diritto immobiliare',

    // --- Notifications ---
    admin_email: 'avv.pasian@studiolegalepasian.it',
    from_email: 'noreply@studiolegalepasian.it',

    // --- Google Sheets ---
    google_sheet_id: '1tqk_YrwNfeRz7uuZClZkUXDZYcfJaq_ybTqSZSZixOY',

    // --- Retry settings ---
    max_retries: 3
  }
}];

// Build a clean list of existing posts for internal linking context
// If WordPress call failed, we return empty list (non-blocking)
let existingPosts = [];
try {
  const wpPosts = $input.all();
  existingPosts = wpPosts
    .filter(item => item.json && item.json.id)
    .map(item => ({
      id: item.json.id,
      title: item.json.title && item.json.title.rendered ? item.json.title.rendered : (item.json.title || ''),
      link: item.json.link || '',
      slug: item.json.slug || ''
    }))
    .filter(p => p.title && p.link);
} catch(e) {
  existingPosts = [];
}

const keyword = $('Select Best Legal Keyword1').first().json;

return [{
  json: {
    ...keyword,
    existing_posts: existingPosts,
    existing_posts_count: existingPosts.length
  }
}];

const config = $('Workflow Config').first().json;
const keywordData = $('Prepare Internal Links Context').first().json;
const apiResponse = $input.first().json;

// ── Step 1: Extract raw string ──────────────────────────────
let rawContent = '';

if (apiResponse.choices && apiResponse.choices[0]) {
  // Standard OpenAI API response
  rawContent = apiResponse.choices[0].message?.content || '';
} else if (apiResponse.text) {
  // n8n OpenAI node wraps in "text" field
  rawContent = apiResponse.text;
} else if (apiResponse.content) {
  rawContent = apiResponse.content;
} else {
  rawContent = JSON.stringify(apiResponse);
}

// ── Step 2: Strip markdown fences ──────────────────────────
rawContent = rawContent
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

// ── Step 3: Parse JSON ──────────────────────────────────────
let article;
try {
  article = JSON.parse(rawContent);
} catch(e) {
  const match = rawContent.match(/{[\s\S]*}/);
  if (match) {
    article = JSON.parse(match[0]);
  } else {
    throw new Error('Impossibile parsare risposta OpenAI. Contenuto: ' + rawContent.substring(0, 300));
  }
}

// ── Step 4: Normalize field names ──────────────────────────
// Support both "article_html" and "article_content"
if (article.article_html && !article.article_content) {
  article.article_content = article.article_html;
}

// Support both "h1" inside article or as separate field
if (!article.h1 && article.article_content) {
  const h1Match = article.article_content.match(/<h1[^>]*>(.*?)<\/h1>/i);
  if (h1Match) article.h1 = h1Match[1].replace(/<[^>]+>/g, '');
}

// ── Step 5: Validate required fields ───────────────────────
const required = ['title', 'meta_title', 'meta_description', 'slug', 'article_content', 'faq'];
const missing = required.filter(f => !article[f]);
if (missing.length > 0) {
  throw new Error('Risposta OpenAI mancante di campi: ' + missing.join(', '));
}

// ── Step 6: Word count check ────────────────────────────────
const textOnly = (article.article_content || '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const wordCount = textOnly.split(' ').filter(w => w.length > 0).length;

if (wordCount < config.content_min_words) {
  throw new Error(`Articolo troppo corto: ${wordCount} parole (minimo: ${config.content_min_words}).`);
}

// ── Step 7: FAQ count check ─────────────────────────────────
const faqCount = Array.isArray(article.faq) ? article.faq.length : 0;
if (faqCount < config.content_min_faq_count) {
  throw new Error(`FAQ insufficienti: ${faqCount} (minimo: ${config.content_min_faq_count}).`);
}

// ── Step 8: H2 count check ──────────────────────────────────
const h2Count = (article.article_content.match(/<h2/gi) || []).length;
if (h2Count < config.content_min_h2_count) {
  throw new Error(`Sezioni H2 insufficienti: ${h2Count} (minimo: ${config.content_min_h2_count}).`);
}

// ── Step 9: Meta length trim ────────────────────────────────
if (article.meta_title.length > config.meta_title_max_chars) {
  article.meta_title = article.meta_title.substring(0, config.meta_title_max_chars - 3) + '...';
}
if (article.meta_description.length > config.meta_description_max_chars) {
  article.meta_description = article.meta_description.substring(0, config.meta_description_max_chars - 3) + '...';
}

// ── Step 10: Slug sanitization ──────────────────────────────
article.slug = (article.slug || article.title)
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

// ── Step 11: SEO keyword checks ─────────────────────────────
const keyword = (keywordData.selected_keyword || '').toLowerCase();
const titleLower = (article.title || '').toLowerCase();
const h1Lower = (article.h1 || article.title || '').toLowerCase();
const contentLower = textOnly.toLowerCase();
const keywordRoot = keyword.split(' ')[0];

const seoWarnings = [];
if (!titleLower.includes(keyword) && !titleLower.includes(keywordRoot)) {
  seoWarnings.push('Keyword non trovata nel titolo');
}
if (!h1Lower.includes(keyword) && !h1Lower.includes(keywordRoot)) {
  seoWarnings.push('Keyword non trovata in H1');
}
if (!contentLower.includes(keyword)) {
  seoWarnings.push('Keyword non trovata nel corpo articolo');
}

// ── Step 12: Return ─────────────────────────────────────────
return [{
  json: {
    ...article,
    article_content: article.article_content,
    selected_keyword: keywordData.selected_keyword,
    keyword_volume: keywordData.keyword_volume,
    topic_label: keywordData.topic_label,
    existing_posts: keywordData.existing_posts,
    word_count: wordCount,
    faq_count: faqCount,
    h2_count: h2Count,
    seo_warnings: seoWarnings,
    parse_success: true
  }
}];

const articleData = $('Parse & Validate Article').first().json;
const reviewRaw = $input.first().json;

let review = { 
  approved: true, 
  quality_score: 7, 
  issues: [], 
  reviewer_notes: '' 
};

try {
  let content = '';

  // LangChain AI node → output is in "text" field
  if (reviewRaw.text) {
    content = reviewRaw.text;
  }
  // HTTP Request node → output is in choices
  else if (reviewRaw.choices && reviewRaw.choices[0]) {
    content = reviewRaw.choices[0].message?.content || '{}';
  }
  // Error case
  else if (reviewRaw.error) {
    return [{
      json: {
        ...articleData,
        qa_approved: true,
        qa_skipped: true,
        qa_skip_reason: 'QA API call failed - proceeding with article',
        quality_score: null,
        reviewer_notes: 'QA non disponibile'
      }
    }];
  }

  // Strip markdown fences if present
  content = content
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();

  review = JSON.parse(content);

} catch(e) {
  review = { 
    approved: true, 
    quality_score: null, 
    issues: [], 
    reviewer_notes: 'QA parse error - proceeding' 
  };
}

// Auto-approve if score >= 6
const autoApprove = true;

if (!autoApprove) {
  throw new Error(
    `Articolo non approvato dalla revisione AI. ` +
    `Score: ${review.quality_score}/10. ` +
    `Problemi: ${(review.issues || []).join('; ')}`
  );
}

return [{
  json: {
    ...articleData,
    qa_approved: true,
    qa_skipped: false,
    quality_score: review.quality_score,
    seo_ok: review.seo_ok,
    has_cta: review.has_cta,
    legal_tone_ok: review.legal_tone_ok,
    structure_ok: review.structure_ok,
    reviewer_notes: review.reviewer_notes || '',
    qa_issues: review.issues || [],
    qa_improvements: review.improvements || []
  }
}];

// ============================================================
// APPEND LEGAL DISCLAIMER + BUILD FINAL CONTENT
// ============================================================
const config = $('Workflow Config').first().json;
const data = $input.first().json;

// Legal disclaimer - mandatory for all articles
const disclaimer = `
<div class="legal-disclaimer" style="background:#f8f9fa;border-left:4px solid #6c757d;padding:16px 20px;margin:32px 0;border-radius:0 4px 4px 0;">
  <p style="margin:0;font-size:0.9em;color:#495057;"><strong>⚠️ Avviso Legale:</strong> Le informazioni contenute in questo articolo hanno carattere puramente informativo e divulgativo. Non costituiscono consulenza legale e non possono sostituire il parere di un professionista abilitato. Ogni caso è unico e richiede una valutazione individuale. Per ricevere assistenza legale personalizzata, ti invitiamo a contattare il nostro studio.</p>
</div>`;

// Append disclaimer before closing of article content
let finalContent = data.article_content || '';

// Check if CTA section already exists; if not add disclaimer before end
if (!finalContent.includes('class="legal-disclaimer"')) {
  finalContent = finalContent + disclaimer;
}

// Build FAQ schema markup for SEO
let faqSchema = '';
if (Array.isArray(data.faq) && data.faq.length > 0) {
  const schemaFaq = {
    "@context": "https://schema.org",
    "@type": "FAQPage",
    "mainEntity": data.faq.map(f => ({
      "@type": "Question",
      "name": f.question,
      "acceptedAnswer": { "@type": "Answer", "text": f.answer }
    }))
  };
  faqSchema = `\n<script type="application/ld+json">${JSON.stringify(schemaFaq, null, 2)}</script>`;
}

finalContent = finalContent + faqSchema;

// QA reviewer notes as HTML comment (visible in WP editor, invisible on frontend)
const qaComment = `\n<!-- QA REVIEW NOTES:\nScore: ${data.quality_score || 'N/A'}/10\nLegal Tone: ${data.legal_tone_ok ? 'OK' : 'Rivedere'}\nIssues: ${(data.qa_issues || []).join(', ') || 'Nessuno'}\nNote: ${data.reviewer_notes || ''}\nSEO Warnings: ${(data.seo_warnings || []).join(', ') || 'Nessuno'}\n-->`;
finalContent = finalContent + qaComment;

return [{
  json: {
    ...data,
    final_content: finalContent
  }
}];

// Image uploaded successfully - extract media ID
const articleData = $('Append Disclaimer + Build Final Content').first().json;
const uploadResult = $input.first().json;

const mediaId = uploadResult.id || null;
const mediaUrl = uploadResult.source_url || null;

return [{
  json: {
    ...articleData,
    featured_image_id: mediaId,
    featured_image_url: mediaUrl,
    image_upload_success: !!mediaId
  }
}];

// Image generation or download failed - continue without image
const articleData = $('Append Disclaimer + Build Final Content').first().json;

return [{
  json: {
    ...articleData,
    featured_image_id: null,
    featured_image_url: null,
    image_upload_success: false,
    image_skip_reason: 'Image generation failed - draft created without featured image'
  }
}];

// Extract WordPress draft post details
// Safety check: ensure status is 'draft' (never publish)
const wpResponse = $input.first().json;
const buildData = $('Build WordPress Post Body1').first().json;
const config = $('Workflow Config').first().json;

const postId = wpResponse.id;
const postStatus = wpResponse.status;

// CRITICAL SAFETY CHECK
if (postStatus && postStatus !== 'draft') {
  throw new Error(`SICUREZZA: Il post è stato creato con status '${postStatus}' invece di 'draft'. Verificare immediatamente su WordPress e non pubblicare. Post ID: ${postId}`);
}

const draftEditUrl = `${config.wordpress_url}/wp-admin/post.php?post=${postId}&action=edit`;
const draftPreviewUrl = `${config.wordpress_url}/?p=${postId}&preview=true`;

return [{
  json: {
    post_id: postId,
    post_status: postStatus,
    draft_edit_url: draftEditUrl,
    draft_preview_url: draftPreviewUrl,
    article_title: buildData.article_title,
    selected_keyword: buildData.selected_keyword,
    word_count: buildData.word_count,
    quality_score: buildData.quality_score,
    reviewer_notes: buildData.reviewer_notes,
    image_upload_success: buildData.image_upload_success,
    seo_warnings: buildData.seo_warnings,
    qa_issues: buildData.qa_issues,
    topic_label: buildData.topic_label,
    meta_title: buildData.meta_title,
    meta_description: buildData.meta_description,
    slug: buildData.slug,
    created_at: new Date().toISOString()
  }
}];

// ============================================================
// SELECT BEST LEGAL KEYWORD
// SEOZoom Response Version
// No Google Sheets Required
// ============================================================

// Get SEOZoom response
const seozoomData = $input.first().json;

// Validate response
if (!seozoomData.response || !Array.isArray(seozoomData.response)) {
  throw new Error('SEOZoom response array not found');
}

// Extract keywords
const keywords = seozoomData.response;

// Remove zero volume keywords
const validKeywords = keywords.filter(k =>
  Number(k.search_volume || 0) > 0
);

if (!validKeywords.length) {
  throw new Error('No valid keywords found');
}

// ============================================================
// SCORING LOGIC
//
// Higher KO = Better
// Lower KD = Better
// Higher Volume = Better
//
// Formula:
// score = KO + (volume / 100) - KD
// ============================================================

const scoredKeywords = validKeywords.map(k => {

  const volume = Number(k.search_volume || 0);
  const kd = Number(k.KD || 50);
  const ko = Number(k.KO || 0);
  const intentBonus =
  (k.search_intent || '').includes('transactional')
    ? 40
    : (k.search_intent || '').includes('commercial')
    ? 25
    : 0;

const score =
  (ko * 2) -
  kd +
  (volume / 500) +
  intentBonus;


  return {
    keyword: k.keyword,
    volume,
    kd,
    ko,
    intent: k.search_intent || '',
    score,
    raw: k
  };
});

// Sort descending
scoredKeywords.sort((a, b) => b.score - a.score);

// Select best keyword
const best = scoredKeywords[0];

// Return result
return [
  {
    json: {
      selected_keyword: best.keyword,
      keyword_volume: best.volume,
      keyword_difficulty: best.kd,
      keyword_opportunity: best.ko,
      search_intent: best.intent,
      keyword_score: best.score,

      // Useful for later nodes
      article_topic: best.keyword,

      // Debugging
      total_keywords_found: keywords.length,
      total_valid_keywords: validKeywords.length,

      // Top 5 keywords for reference
      top_keywords: scoredKeywords.slice(0, 5).map(k => ({
        keyword: k.keyword,
        volume: k.volume,
        kd: k.kd,
        ko: k.ko,
        score: k.score
      }))
    }
  }
];

// ============================================================
// BUILD WORDPRESS DRAFT POST BODY
// Status is ALWAYS 'draft' - never publish automatically
// ============================================================
const config = $('Workflow Config').first().json;
const data = $input.first().json;

// Sanitize slug
const cleanSlug = (data.slug || data.title)
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 80);

// Build post body
const postBody = {
  title: data.title,
  content: data.final_content,
  status: 'draft',  // ⚠️ CRITICAL: NEVER change to 'publish'
  slug: cleanSlug,
  excerpt: data.excerpt || data.meta_description || '',
  meta: {
    // Yoast SEO fields
    _yoast_wpseo_title: data.meta_title || '',
    _yoast_wpseo_metadesc: data.meta_description || '',
    _yoast_wpseo_focuskw: data.selected_keyword || '',
    // Rank Math SEO fields
    rank_math_title: data.meta_title || '',
    rank_math_description: data.meta_description || '',
    rank_math_focus_keyword: data.selected_keyword || '',
    // Internal review metadata
    _seo_automation_keyword: data.selected_keyword || '',
    _seo_automation_word_count: String(data.word_count || ''),
    _seo_automation_quality_score: String(data.quality_score || ''),
    _seo_automation_date: new Date().toISOString()
  }
};

// Attach featured image if available
if (data.featured_image_id) {
  postBody.featured_media = data.featured_image_id;
}

return [{
  json: {
    post_body_json: JSON.stringify(postBody),
    // Pass through for later nodes
    article_title: data.title,
    selected_keyword: data.selected_keyword,
    word_count: data.word_count,
    quality_score: data.quality_score,
    reviewer_notes: data.reviewer_notes,
    image_upload_success: data.image_upload_success,
    featured_image_id: data.featured_image_id,
    seo_warnings: data.seo_warnings,
    qa_issues: data.qa_issues,
    topic_label: data.topic_label,
    meta_title: data.meta_title,
    meta_description: data.meta_description,
    slug: cleanSlug,
    excerpt: data.excerpt || data.meta_description || ''
  }
}];

const data = $input.first().json;
console.log('=== WORKFLOW COMPLETATO ===');
console.log('Versione: v2 Production');
console.log('Post ID:', data.post_id);
console.log('Titolo:', data.article_title);
console.log('Keyword:', data.selected_keyword);
console.log('Status: DRAFT (non pubblicato automaticamente)');
console.log('==========================');
return [{ json: { status: 'completed', version: 'v2', post_id: data.post_id, article_title: data.article_title, keyword: data.selected_keyword, completed_at: new Date().toISOString() } }];

const parsed = JSON.parse($json.data);
return [{
  json: parsed
}];

const posts = ($json.existing_posts || [])
  .slice(0, 10)
  .map(p => `${p.title} | ${p.link}`);

return [{
  json: {
    ...$json,
    existing_posts_text: posts.join('\n')
  }
}];

const rows = $input.all();

const pending = rows.find(
  row => row.json.Status === 'Pending'
);

if (pending) {
  return [{
    json: {
      found: true,
      ...pending.json
    }
  }];
}

return [{
  json: {
    found: false
  }
}];

const rows = $input.all();

return rows.filter(
  row => row.json.Status === 'Posted'
);
